---@class LFightBuffExpress 战斗技能
local LFightBuffExpress = LxClass("LFightBuffExpress", nil)

local LFightExpreRoleAct = LXImport("..Expression.LFightExpreRoleAct")
local LFightExpreEffect = LXImport("..Expression.LFightExpreEffect")
local LFightExpreDrawing = LXImport("..Expression.LFightExpreDrawing")
local LFightExpreTransform = LXImport("..Expression.LFightExpreTransform")
local LFightExpreHitHud = LXImport("..Expression.LFightExpreHitHud")
local LFightExpreShake = LXImport("..Expression.LFightExpreShake")

local LBuffExpressData = LXImport("..Data.LBuffExpressData")
--[[
    data =
    {
        expressId,
    }
]]

function LFightBuffExpress:LFightBuffExpress(data)
    self._expressId = data.expressId
    ---@type LFightUnit
    self._manager = data.manager

    local buffExpressData = LBuffExpressData:New()
    buffExpressData:Create(self._expressId)

    ---@type LBuffExpressData
    self._buffExpressData = buffExpressData


    self:CreateExpressions()

end

function LFightBuffExpress:CalcSkillPlayTime()
    local playList = self._buffExpressData:GetPlayList()
    return gModelSkill:CalcSkillTime(playList)
end

function LFightBuffExpress:CreateExpressions()
    local playList = self._buffExpressData:GetPlayList()
    local expressionsTransformList = {}
    local expressionsList = {}
    local showHit = false
    local expre = nil
    for k,v in ipairs(playList) do
        expre = nil
        if v.effType == LSkillEffConst.PLAY_EFF_ANI then
            expre = LFightExpreRoleAct:New(self._manager)
        elseif v.effType == LSkillEffConst.PLAY_EFF_EFFECT then
            expre = LFightExpreEffect:New(self._manager)
        elseif v.effType == LSkillEffConst.PLAY_EFF_DRAWING then
            expre:Create(v)
        elseif v.effType == LSkillEffConst.PLAY_EFF_HIT_HUD then
            expre = LFightExpreHitHud:New(self._manager)
        elseif v.effType == LSkillEffConst.PLAY_EFF_SHAKE then
            expre = LFightExpreShake:New(self._manager)
        end
        if expre then
            expre:Create(v)
            table.insert(expressionsList,expre)
        end

        if v.effType == LSkillEffConst.PALY_OBJ_TRANSFORM then
            local tExpre = LFightExpreTransform:New(self._manager)
            tExpre:Create(v)
            table.insert(expressionsTransformList,tExpre)
        end
    end

    self._expressionList = expressionsList

    self._expressionsTransformList = expressionsTransformList
end

function LFightBuffExpress:Preload()
    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            v:Preload()
        end
    end
    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            v:Preload()
        end
    end
end

function LFightBuffExpress:StartRun(data)
    --local time = data.curTime
    ---@type LFightObject
    local targetObj = data.targetObj
    ---@type LFightObject
    self._targetObj = targetObj
    --if targetObj then
    --    targetObj:SetSkillPlaying(true)
    --end

    local targetObjs = data.targetObjs or {}
    ---@type LFightObject[]
    self._targetObjs = targetObjs

    self._buffEffShowPos = data.buffEffShowPos

    self._atkObj = data.atkObj

    ---@type boolean
    self._isSummonBuff = data.isSummonBuff

    ---@type boolean
    self._isBombBuff = data.isBombBuff

    ---@type LFightObject
    self._summonHero = data.summonHero

    --- 标记类型，如果是 3 的话，死亡后复活需要重新把特效显示出来
    self._buffEffShowType = data.buffEffShowType or -1

    self._isStart = false

    self:OnRun(data.curTime)

end

function LFightBuffExpress:CheckReady()
    local targetObjs = self._targetObjs
    if targetObjs and #targetObjs > 0 then
        local targetCnt = #targetObjs
        local readyCnt = 0
        for i,v in ipairs(targetObjs) do
            if v:IsObjReady() then
                readyCnt = readyCnt + 1
            end
        end
        if readyCnt < targetCnt then
            return
        end
    else
        if not self._targetObj then
            return
        end

        if not self._targetObj:IsObjReady() then
            return
        end
    end

    return true
end

function LFightBuffExpress:StartRunInter(time)
    if self._isStart then
        return
    end
    self._isStart = true
    local battleUnit = self._manager
    local targetObj = self._targetObj
    local targetObjs = self._targetObjs

    ---@type number 标记类型，如果是 3 的话，死亡后复活需要重新把特效显示出来
    local buffEffShowType = self._buffEffShowType or -1

    ---@type LFightObject
    local summonHero = self._summonHero
    local rootTrans = battleUnit:GetEffectRootTrans()
    local rundata = nil
    for k,v in pairs(self._expressionList) do
        local type = v:GetType()
        if type == LSkillEffConst.PLAY_EFF_ANI then
            rundata = {
                curTime = time,
                targetObj = targetObj,
            }
            v:BeginRunning(rundata)
        elseif type == LSkillEffConst.PLAY_EFF_EFFECT then
            local effTarget = v:GetEffTarget()
            local dataList = {}
            if effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
                if targetObjs and #targetObjs > 0 then
                    for i,heroObj in ipairs(targetObjs) do
                        table.insert(dataList,self:GetEffectPara(heroObj,rootTrans))
                    end
                else
                    table.insert(dataList,self:GetEffectPara(targetObj,rootTrans))
                end
            elseif effTarget == LFightConst.EFFECT_TO_SELF_TEAM_CENTER then
                --4=我方九宫中心格
                local dir = targetObj:GetSide()
                table.insert(dataList,{
                    trans = rootTrans,
                    pos = battleUnit:GetFormationCenterPosition(dir):Clone(),
                    dir = dir,
                    targetObj = targetObj,
                })
            elseif effTarget == LFightConst.EFFECT_TO_ENEMY_TEAM_CENTER then
                --5=敌方九宫中心格
                local dir = targetObj:GetSide()
                table.insert(dataList,{
                    trans = rootTrans,
                    pos = battleUnit:GetFormationCenterPosition(battleUnit:GetOppositeSide(dir)):Clone(),
                    dir = dir,
                    targetObj = targetObj,
                })
            elseif effTarget == LFightConst.EFFECT_TO_SUMMON then
                --- 召唤物可能还没出来，所以只能自己组织数据
                if summonHero then
                    table.insert(dataList,{
                        trans = rootTrans,
                        pos = summonHero:GetGridPos(),
                        dir = summonHero:GetDirection(),
                        targetObj = summonHero,
                    })
                end
            else
                table.insert(dataList,self:GetEffectPara(targetObj,rootTrans))
            end
            rundata = {
                curTime = time,
                isUpperLayer = targetObj:IsUpperLayer(),
                dataList = dataList,
                buffEffShowType = buffEffShowType,
            }
            v:BeginRunning(rundata)
        elseif type == LSkillEffConst.PLAY_EFF_DRAWING then
            rundata = {
                curTime = time,
                targetObj = targetObj,
                atkObj = self._atkObj,
            }
            v:BeginRunning(rundata)
        elseif type == LSkillEffConst.PLAY_EFF_HIT_HUD then
            rundata = {
                curTime = time,
                targetObj = targetObj,
                targetObjs = targetObjs,
            }
            v:BeginRunning(rundata)
        end
    end
    for i,v in ipairs(self._expressionsTransformList) do
        v:BeginRunning({
            curTime = time,
            targetObj = targetObj,
            atkObj = self._atkObj,
        })
    end
end

---@param heroObj LFightObject
function LFightBuffExpress:GetEffectPara(heroObj,rootTrans)
    local isChangeSpine = heroObj:GetChangeSpineState()
    local trans = isChangeSpine and rootTrans or heroObj:GetDpObject():GetDisplayTrans()
    return {
        trans = trans,
        pos = self:GetPosByHeroObj(heroObj),
        dir = heroObj:GetDirection(),
        targetObj = heroObj,
    }
end

---@param heroObj LFightObject
---@return Vector3
function LFightBuffExpress:GetPosByHeroObj(heroObj)
    local pos = heroObj:GetPosition():Clone()
    local buffEffShowPos = self._buffEffShowPos
    if not self._isBombBuff then
        if buffEffShowPos and buffEffShowPos > 0 and not heroObj:GetChangeSpineState() then
            local buffShowPos = heroObj:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,heroObj:GetObjScale())
            if buffShowPos then
                pos = buffShowPos
            end
        end
    end
    return pos
end

function LFightBuffExpress:OnRun(time)
    if not self._expressionList then
        return
    end

    if self:CheckReady() then
        self:StartRunInter(time)
    end

    for k,v in ipairs(self._expressionList) do
        v:Run(time)
    end

    if self._expressionsTransformList then
        for k,v in ipairs(self._expressionsTransformList) do
            v:Run(time)
        end
    end
end

function LFightBuffExpress:GetExpressId()
    return self._expressId
end

function LFightBuffExpress:Destroy()
    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            v:Destroy()
        end
        self._expressionList = nil
    end
    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            v:Destroy()
        end
        self._expressionsTransformList = nil
    end
    self._isDestroy = true
end

function LFightBuffExpress:IsEnd()

    for k,v in ipairs(self._expressionList) do
        if not v:IsEnd() then
            return false
        end
    end

    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            if not v:IsEnd() then
                return false
            end
        end
    end

    return true
end

function LFightBuffExpress:OnRecycle()
    for k,v in ipairs(self._expressionList) do
        v:OnRecycle()
    end

    if self._expressionsTransformList then
        for i,v in ipairs(self._expressionsTransformList) do
            v:OnRecycle()
        end
    end
end

function LFightBuffExpress:OnPlayEnd()
    local targetObj = self._targetObj
    if targetObj then
        targetObj:SetSkillPlaying(false)
    end
end

function LFightBuffExpress:IsDestroy()
    return self._isDestroy
end

function LFightBuffExpress:IsPersistenceWait()
    if self:IsDestroy() then return false end

    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            if v:IsPersistenceWait() then return true end
        end
    end

    if self._expressionsTransformList then
        for k,v in ipairs(self._expressionsTransformList) do
            if v:IsPersistenceWait() then return true end
        end
    end
    return false
end

function LFightBuffExpress:RecycleSpecialExpre()
    if self:IsDestroy() then return end

    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            v:RecycleEnd()
        end
    end

    if self._expressionsTransformList then
        for k,v in ipairs(self._expressionsTransformList) do
            v:RecycleEnd()
        end
    end
end

function LFightBuffExpress:SetVisible(bShow)
    if self:IsDestroy() then return end

    if self._expressionList then
        for k,v in ipairs(self._expressionList) do
            v:SetVisible(bShow)
        end
    end

    if self._expressionsTransformList then
        for k,v in ipairs(self._expressionsTransformList) do
            v:SetVisible(bShow)
        end
    end
end

return LFightBuffExpress